import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../api/axios";
import "./styles/Books.css";

function LibrarianBooks() {
  const navigate = useNavigate();

  const role = localStorage.getItem("role");

  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");

  useEffect(() => {
    if (role !== "Librarian") return;

    const fetchBooks = async () => {
      try {

        // 🔥 get ALL books
        const res = await api.get(`/books`);

        setBooks(res.data);

      } catch (err) {
        console.log("Error fetching books:", err);
      }

      setLoading(false);
    };

    fetchBooks();

  }, [role]);

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this book?")) {
      try {
        await api.delete(`/books/${id}`);
        setBooks(books.filter((book) => book._id !== id));
      } catch (err) {
        console.error("Error deleting book:", err);
        alert("Failed to delete book.");
      }
    }
  };

  if (loading) {
    return <p style={{ padding: "40px" }}>Loading books...</p>;
  }

  return (
    <div className="books-page">

      <h1 className="books-title">All Library Books</h1>
      
      <div style={{ marginBottom: "20px", display: "flex", justifyContent: "center" }}>
        <input 
          type="text" 
          placeholder="Search by title or author..." 
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          style={{ width: "100%", maxWidth: "400px", padding: "10px", borderRadius: "8px", border: "1px solid #ccc", outline: "none" }}
        />
      </div>

      {(() => {
        const filteredBooks = books.filter((book) => 
          book.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
          book.author.toLowerCase().includes(searchQuery.toLowerCase())
        );

        if (filteredBooks.length === 0) {
          return <p>No books found.</p>;
        }

        const groupedBooks = filteredBooks.reduce((acc, book) => {
          const genre = book.genre || book.category || "Uncategorized";
          if (!acc[genre]) {
            acc[genre] = [];
          }
          acc[genre].push(book);
          return acc;
        }, {});

        return Object.keys(groupedBooks).sort().map((genre) => (
          <div key={genre} style={{ marginBottom: "50px" }}>
            <h2 style={{ 
              color: "#3e2723", 
              borderBottom: "2px solid #8d6e63", 
              paddingBottom: "10px", 
              marginBottom: "20px", 
              textAlign: "left",
              paddingLeft: "10px"
            }}>
              {genre} Section
            </h2>
            <div className="books-grid">
              {groupedBooks[genre].map((book) => (
                <div key={book._id} className="book-card">
                  <img src={book.cover} alt={book.title} className="book-cover" />
                  <h3>{book.title}</h3>
                  <p>{book.author}</p>
                  
                  <div style={{ display: "flex", gap: "10px", marginTop: "10px" }}>
                    <button 
                      onClick={() => navigate(`/edit-book/${book._id}`)}
                      style={{ flex: 1, padding: "8px", background: "#4caf50", color: "#fff", border: "none", borderRadius: "4px", cursor: "pointer" }}
                    >
                      Edit
                    </button>
                    <button 
                      onClick={() => handleDelete(book._id)}
                      style={{ flex: 1, padding: "8px", background: "#f44336", color: "#fff", border: "none", borderRadius: "4px", cursor: "pointer" }}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ));
      })()}

    </div>
  );
}

export default LibrarianBooks;
